1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const result: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx !== 0 || dy !== 0) {
10	        result.push([x + dx, y + dy]);
11	      }
12	    }
13	  }
14	  return result;
15	};
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveSet = new Set(cells.map(cellKey));
19	
20	  const liveNeighborCounts = new Map<string, { cell: Cell; count: number }>();
21	  for (const cell of cells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const key = cellKey(neighbor);
24	      const entry = liveNeighborCounts.get(key) ?? { cell: neighbor, count: 0 };
25	      entry.count++;
26	      liveNeighborCounts.set(key, entry);
27	    }
28	  }
29	
30	  const nextGen: Cell[] = [];
31	  for (const [key, { cell, count }] of liveNeighborCounts) {
32	    const isAlive = liveSet.has(key);
33	    if (count === 3 || (isAlive && count === 2)) {
34	      nextGen.push(cell);
35	    }
36	  }
37	
38	  return nextGen;
39	}
