1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single living cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent living cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("transforms a vertical blinker into a horizontal blinker", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(vertical);
23	    expect(result).toHaveLength(3);
24	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
25	  });
26	  it("kills a live cell with 4 or more neighbors (overpopulation)", () => {
27	    // Center cell (1,1) surrounded by 8 live neighbors -> dies
28	    const cells: [number, number][] = [
29	      [0, 0], [1, 0], [2, 0],
30	      [0, 1], [1, 1], [2, 1],
31	      [0, 2], [1, 2], [2, 2],
32	    ];
33	    const result = nextGeneration(cells);
34	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
35	  });
36	  it("brings a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
37	    // L-shape: dead cell (1,1) has 3 live neighbors -> becomes alive
38	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
39	    const result = nextGeneration(cells);
40	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
41	  });
42	  it("handles negative coordinates correctly", () => {
43	    // Vertical blinker centered at (-5, 0)
44	    const vertical: [number, number][] = [[-5, -1], [-5, 0], [-5, 1]];
45	    const result = nextGeneration(vertical);
46	    expect(result).toHaveLength(3);
47	    expect(result).toEqual(
48	      expect.arrayContaining([[-6, 0], [-5, 0], [-4, 0]])
49	    );
50	  });
51	});
