const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(cellKey));

  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key) ?? { cell: neighbor, count: 0 };
      entry.count++;
      neighborCounts.set(key, entry);
    }
  }

  return Array.from(neighborCounts)
    .filter(([key, { count }]) => survives(liveSet.has(key), count))
    .map(([, { cell }]) => cell);
}

